class Solution:
    def checkPalindromeFormation(self, a: str, b: str) -> bool:
        def is_palindrome(s, left, right):
            while left < right:
                if s[left] != s[right]:
                    return False
                left += 1
                right -= 1
            return True

        n = len(a)
        def check(a, b):
            i = 0
            j = n - 1
            while i < j:
                if a[i] != b[j]:
                    return is_palindrome(b, i, n - 1) or is_palindrome(a, 0, j)
                i += 1
                j -= 1
            return True

        return check(a, b) or check(b, a)
